1	//! Array operations: reshape, transpose, element-wise arithmetic.
2	
3	use crate::dense::DenseArray;
4	use crate::error::ArrayError;
5	use crate::shape::Shape;
6	
7	impl DenseArray {
8	    /// Reshape to a new shape, preserving element order.
9	    ///
10	    /// Succeeds only when the new shape has the same element count.
11	    pub fn reshape(&self, new_shape: Shape) -> Result<DenseArray, ArrayError> {
12	        let source = self.elem_count();
13	        let target = new_shape.elem_count();
14	        if source != target {
15	            return Err(ArrayError::ShapeMismatch { source, target });
16	        }
17	        Ok(DenseArray {
18	            shape: new_shape,
19	            data: self.data.clone(),
20	            labels: None,
21	        })
22	    }
23	
24	    /// Transpose: reverse axis order and reorder data to row-major.
25	    ///
26	    /// - Scalar/vector: returns a clone (identity).
27	    /// - Matrix and higher: reverses dims and physically reorders data.
28	    #[must_use]
29	    pub fn transpose(&self) -> DenseArray {
30	        let dims = self.shape().dims();
31	        if dims.len() <= 1 {
32	            return self.clone();
33	        }
34	
35	        let new_dims: Vec<usize> = dims.iter().rev().copied().collect();
36	        let new_shape = Shape::new(new_dims);
37	        let n = self.elem_count();
38	        let mut new_data = vec![0.0; n];
39	
40	        let rank = dims.len();
41	        let old_strides = compute_strides(dims);
42	        let new_strides = compute_strides(new_shape.dims());
43	
44	        for flat in 0..n {
45	            let mut remainder = flat;
46	            let mut new_flat = 0;
47	            for axis in 0..rank {
48	                let idx = remainder / old_strides[axis];
49	                remainder %= old_strides[axis];
50	                new_flat += idx * new_strides[rank - 1 - axis];
51	            }
52	            new_data[new_flat] = self.data[flat];
53	        }
54	
55	        let labels = self
56	            .labels
57	            .as_ref()
58	            .map(|lbls| lbls.iter().rev().cloned().collect());
59	
60	        DenseArray {
61	            shape: new_shape,
62	            data: new_data,
63	            labels,
64	        }
65	    }
66	}
67	
68	impl DenseArray {
69	    /// Apply a binary operation element-wise with scalar broadcasting.
70	    ///
71	    /// - Same shape: element-wise.
72	    /// - One scalar: broadcast to the other's shape.
73	    /// - Otherwise: ShapeMismatch error.
74	    ///
75	    /// Label propagation (Saga 11.5 Phase 3): scalar operands contribute
76	    /// no labels, so the non-scalar side's labels win unconditionally.
77	    /// For same-shape operands: if either side is unlabeled, the
78	    /// labeled side's labels carry through; if both are labeled, the
79	    /// label vectors must match or `LabelMismatch` is raised.
80	    pub fn apply_binop(
81	        &self,
82	        other: &DenseArray,
83	        op: fn(f64, f64) -> f64,
84	    ) -> Result<DenseArray, ArrayError> {
85	        let result_labels = merge_labels(self, other)?;
86	        if self.shape() == other.shape() {
87	            let data: Vec<f64> = self
88	                .data()
89	                .iter()
90	                .zip(other.data().iter())
91	                .map(|(a, b)| op(*a, *b))
92	                .collect();
93	            return Ok(DenseArray {
94	                shape: self.shape.clone(),
95	                data,
96	                labels: result_labels,
97	            });
98	        }
99	        // Scalar broadcast
100	        if self.rank() == 0 {
101	            let s = self.data()[0];
102	            let data: Vec<f64> = other.data().iter().map(|b| op(s, *b)).collect();
103	            return Ok(DenseArray {
104	                shape: other.shape.clone(),
105	                data,
106	                labels: result_labels,
107	            });
108	        }
109	        if other.rank() == 0 {
110	            let s = other.data()[0];
111	            let data: Vec<f64> = self.data().iter().map(|a| op(*a, s)).collect();
112	            return Ok(DenseArray {
